import "server-only";

import { Unkey } from "@unkey/api";

export const unkey = new Unkey({ rootKey: process.env.UNKEY_ROOT_KEY! });

import { unkey } from "./client";

export async function createUnkeyApiKey(ownerId: string) {
  return unkey.keys.create({
    apiId: process.env.UNKEY_API_ID!,
    ownerId,
    prefix: "sf",
  });
}

export async function verifyUnkeyApiKey(key: string) {
  return unkey.keys.verify({ key });
}

import { NextResponse } from "next/server";

import { verifyUnkeyApiKey } from "@/lib/unkey/api-keys";

export async function POST(request: Request) {
  const { key } = await request.json();
  const result = await verifyUnkeyApiKey(key);
  return NextResponse.json(result);
}

const deployChecks = [
  "Create the vendor project and add production env vars",
  "Run the included smoke route after deploy",
  "Document alerting, retries, and rollback behavior",
];

export default function UnkeyAPIKeysPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Unkey API Keys</h1>
        <p className="text-muted-foreground">Managed API key lifecycle and verification for developer platforms.</p>
      </div>
      <div className="grid gap-3">
        {deployChecks.map((check) => (
          <div key={check} className="rounded-lg border p-4 text-sm">{check}</div>
        ))}
      </div>
    </main>
  );
}
